aeA(){this.a8(new A.asz(this,new A.BY().CN("T\xfcrk Ceza Kanunu madde 141 uyar\u0131nca, h\u0131rs\u0131zl\u0131k su\xe7unun cezas\u0131 1 y\u0131ldan 3 y\u0131la kadar hapis cezas\u0131d\u0131r.\nCeza Muhakemesi Kanunu m.91 gere\u011fince g\xf6zalt\u0131 s\xfcresi 24 saati ge\xe7emez.\nBor\xe7lar hukukunda zamana\u015f\u0131m\u0131 s\xfcresi genel olarak 10 y\u0131ld\u0131r.\n\u0130cra ve \u0130flas Kanunu madde 68 uyar\u0131nca, bor\xe7luya \xf6deme emri tebli\u011f edildikten sonra 7 g\xfcn i\xe7inde itiraz edebilir.\nBir kimsenin ba\u015fkas\u0131n\u0131n ta\u015f\u0131nmaz\u0131 \xfczerinde y\xfckl\xfc bir alacak hakk\u0131 elde etmesine ipotek denir.\nMahkemenin daval\u0131 lehine karar vermesine ve san\u0131\u011f\u0131n su\xe7suz bulunmas\u0131na beraat denir.\nTaraflar\u0131n mahkeme d\u0131\u015f\u0131nda anla\u015farak uyu\u015fmazl\u0131\u011f\u0131 \xe7\xf6zmesine arabuluculuk denir.\nDavan\u0131n bir \xfcst mahkemede incelenmesi talebi temyiz olarak adland\u0131r\u0131l\u0131r.\nH\xe2kim, delilleri serbest\xe7e de\u011ferlendirerek san\u0131\u011f\u0131n mahkumiyetine karar verirse mahkumiyet karar\u0131 verilmi\u015f say\u0131l\u0131r.\nCeza Kanunu madde 53 uyar\u0131nca, belli haklar\u0131 kullanmaktan yoksun b\u0131rakma 5 y\u0131la kadar uygulanabilir.\nKasten yaralama halinde, ma\u011fdurun \u015fikayeti durumunda 6 ay i\xe7inde dava a\xe7\u0131lmal\u0131d\u0131r.\nA\u011f\u0131rla\u015ft\u0131r\u0131lm\u0131\u015f m\xfcebbet hapis cezas\u0131, en a\u011f\u0131r ceza t\xfcr\xfcd\xfcr.\nBilirki\u015fi raporu 30 g\xfcn i\xe7inde mahkemeye sunulmal\u0131d\u0131r.\nTan\u0131k, duru\u015fmada yeminli olarak ifade verir.\nVelayet hakk\u0131, \xe7ocu\u011fun yarar\u0131na g\xf6re d\xfczenlenir.\n\u0130ddianame d\xfczenlenmeden kamu davas\u0131 a\xe7\u0131lamaz.\nNafaka y\xfck\xfcml\xfcl\xfc\u011f\xfc, taraflar\u0131n mali durumuna g\xf6re belirlenir.\n")))},
